import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.Cnz97o_5.js";const g=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":1782499736000}'),i={name:"release-notes.md"};function l(s,e,n,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="_0-5-4" tabindex="-1">0.5.4 <a class="header-anchor" href="#_0-5-4" aria-label="Permalink to &quot;0.5.4&quot;">​</a></h2><h3 id="maintenance" tabindex="-1">Maintenance <a class="header-anchor" href="#maintenance" aria-label="Permalink to &quot;Maintenance&quot;">​</a></h3><ul><li>CI pipeline and deployment workflow improvements.</li><li>README and documentation updates.</li></ul><h2 id="_0-5-3" tabindex="-1">0.5.3 <a class="header-anchor" href="#_0-5-3" aria-label="Permalink to &quot;0.5.3&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong><code>pyworkforce.staffing.MultiSkillStaffing</code></strong> — minimum-cost agent-mix optimiser for multi-skill contact-centre staffing. Given per-skill requirements (from <code>ErlangC</code> / <code>ErlangA</code>) and a catalogue of agent skill profiles, solves the integer programme that minimises total weighted headcount. Flexible (multi-skilled) agents count towards every skill they hold, so the solver automatically balances dedicated vs. flexible hiring. Supports an optional <code>max_agents</code> budget cap and is now exported from the <code>pyworkforce</code> root namespace.</li><li><strong><code>pyworkforce.queuing.ErlangB</code></strong> / <strong><code>MultiErlangB</code></strong> — Erlang B (M/M/c/c) pure-loss queue for trunk and channel sizing. Models systems with no waiting room where blocked calls are shed. Provides <code>blocking_probability</code>, <code>achieved_occupancy</code> and <code>required_positions</code> (with <code>max_blocking</code> and <code>max_occupancy</code> targets). <code>MultiErlangB</code> sweeps a parameter grid in parallel, mirroring <code>MultiErlangC</code>.</li><li><strong><code>pyworkforce.breaks.BreakScheduler</code></strong> — CP-SAT solver that assigns break start times to agent slots within each shift while enforcing break windows (earliest start, latest end), preventing overlapping breaks on the same slot, and guaranteeing that simultaneous breaks never exceed the coverage slack. Accepts multiple break types per shift.</li><li><code>ErlangB</code>, <code>MultiErlangB</code>, <code>BreakScheduler</code>, and <code>MultiSkillStaffing</code> are all exported from the <code>pyworkforce</code> root namespace.</li></ul><h3 id="dependency-changes" tabindex="-1">Dependency changes <a class="header-anchor" href="#dependency-changes" aria-label="Permalink to &quot;Dependency changes&quot;">​</a></h3><ul><li>Lowered <code>numpy</code> floor to <code>&gt;=1.23</code> (code uses only stable basic operations; aligns with the <code>pandas&gt;=2.2</code> minimum and unblocks the conda-forge package).</li><li>Lowered <code>ortools</code> floor to <code>&gt;=9.6</code> (all CP-SAT APIs in use are stable at this version; matches the conda-forge <code>ortools-python</code> feedstock).</li></ul><h2 id="_0-5-2-—-previous-release" tabindex="-1">0.5.2 — <em>previous release</em> <a class="header-anchor" href="#_0-5-2-—-previous-release" aria-label="Permalink to &quot;0.5.2 — *previous release*&quot;">​</a></h2><h3 id="new-features-1" tabindex="-1">New features <a class="header-anchor" href="#new-features-1" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong><code>pyworkforce.queuing.ErlangA</code></strong> — M/M/c+M queue with customer abandonment. All metrics computed exactly from the birth-death stationary distribution.</li><li><strong><code>pyworkforce.queuing.MultiErlangA</code></strong> — parameter-grid variant of <code>ErlangA</code>.</li><li><strong><code>pyworkforce.shifts</code></strong> — shift coverage builders (<code>shift_coverage_from_hours</code>, <code>shift_coverage_from_spans</code>, <code>shift_coverage_from_periods</code>, <code>validate_shift_coverage</code>, <code>coverage_to_dataframe</code>).</li><li><strong><code>pyworkforce.utils.results_to_dataframe</code></strong> — tidy DataFrames from <code>Multi*</code> results.</li><li>All estimators expose <code>get_params()</code>, a readable <code>repr()</code> and store their last result as <code>solution_</code>.</li></ul><h3 id="bug-fixes" tabindex="-1">Bug fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug fixes&quot;">​</a></h3><ul><li><code>MultiErlangC</code> now correctly populates <code>achieved_occupancy_params</code> and <code>required_positions_params</code>.</li><li>Validation helpers accept integers where floats are expected and reject booleans, <code>NaN</code> and infinities.</li><li><code>MinHoursRoster</code> rejects duplicate resource names.</li></ul><h3 id="packaging-tooling" tabindex="-1">Packaging &amp; tooling <a class="header-anchor" href="#packaging-tooling" aria-label="Permalink to &quot;Packaging &amp; tooling&quot;">​</a></h3><ul><li>Migrated to PEP 621 <code>pyproject.toml</code>; upgraded dependency floors.</li><li>Added ruff linting, Dependabot config, and a PyPI trusted-publishing workflow.</li><li>Documentation moved to VitePress on GitHub Pages.</li></ul><p>For older releases, see the <a href="https://github.com/rodrigo-arenas/pyworkforce/releases" target="_blank" rel="noreferrer">GitHub releases page</a>.</p>',17)])])}const p=o(i,[["render",l]]);export{g as __pageData,p as default};
